                lit_fiction_books.append({
                    'book_id': row['book_id'],
                    'title': row['title']
                })

print(f"Found {len(lit_fiction_books)} Literature & Fiction books")

# Extract book IDs and create mapping
lit_fiction_book_ids = [book['book_id'] for book in lit_fiction_books]
book_id_to_title = {book['book_id']: book['title'] for book in lit_fiction_books}

print("Sample books:", lit_fiction_books[:5])

# Prepare results
result = {
    'lit_fiction_book_ids': lit_fiction_book_ids,
    'book_id_to_title': book_id_to_title
}

print('__RESULT__:')
print(json.dumps(result))
"}

