{"code": "import json
import pandas as pd
import re

# Load data
books_file = locals()['var_functions.query_db:12']
reviews_file = locals()['var_functions.query_db:24']

# Read data
df_books = pd.read_json(books_file)
df_reviews = pd.read_json(reviews_file)

# Get Literature & Fiction books
lit_fiction_books = []
for idx, row in df_books.iterrows():
    categories_str = row['categories']
    if pd.notna(categories_str):
        try:
            categories_list = json.loads(categories_str.replace("'", '"'))
            if "Literature & Fiction" in categories_list:
                lit_fiction_books.append({
                    'book_id': row['book_id'],
                    'title': row['title']
                })
        except:
            if "Literature & Fiction" in categories_str:
                lit_fiction_books.append({
                    'book_id': row['book_id'],
                    'title': row['title']
                })

# Create mapping
lit_fiction_ids = {book['book_id'] for book in lit_fiction_books}
book_id_to_title = {book['book_id']: book['title'] for book in lit_fiction_books}

print(f"Total Literature & Fiction books: {len(lit_fiction_ids)}")

# Check reviews - try to find pattern
# Extract numeric part from purchase_id and see if it matches book_id pattern
def extract_id_number(id_str):
    match = re.search(r'(bookid|purchaseid)_?(\d+)', str(id_str))
    if match:
        return int(match.group(2))
    return None

# Get all purchase_ids and extract numbers
review_numbers = set()
for idx, row in df_reviews.iterrows():
    num = extract_id_number(row['purchase_id'])
    if num:
        review_numbers.add(num)

print(f"Review ID numbers sample: {sorted(list(review_numbers))[:10]}")
print(f"Book ID numbers sample: {[extract_id_number(bid) for bid in list(lit_fiction_ids)[:10]]}")

# Now try to join - assuming bookid_X maps to purchaseid_X format
# Build a mapping from numeric ID to reviews
def get_reviews_by_id(df_reviews, id_num):
    purchase_id = f'purchaseid_{id_num}'
    return df_reviews[df_reviews['purchase_id'] == purchase_id]

# Check literature & fiction books
print("\n=== CHECKING FOR PERFECT 5.0 RATINGS ===")
perfect_rating_books = []

for book_id in lit_fiction_ids:
    # Extract number from book_id
    book_num = extract_id_number(book_id)
    if not book_num:
        continue

    # Get corresponding purchase_id
    purchase_id = f'purchaseid_{book_num}'
    book_reviews = df_reviews[df_reviews['purchase_id'] == purchase_id]

    if len(book_reviews) > 0:
        # Calculate average rating
        ratings = pd.to_numeric(book_reviews['rating'], errors='coerce')
        avg_rating = ratings.mean()

        if avg_rating == 5.0:
            perfect_rating_books.append({
                'book_id': book_id,
                'title': book_id_to_title[book_id],
                'review_count': len(book_reviews),
                'avg_rating': avg_rating
            })
            print(f"FOUND: {book_id_to_title[book_id]} - {book_id} - Average: {avg_rating}")

print(f"\nTotal perfect 5.0 rating books: {len(perfect_rating_books)}")

print('__RESULT__:')
print(json.dumps(perfect_rating_books))
"}

