df_reviews = pd.read_json(reviews_file)

# Get Literature & Fiction books
lit_fiction_books = []
for idx, row in df_books.iterrows():
    categories_str = row['categories']
    if pd.notna(categories_str):
        try:
            categories_list = json.loads(categories_str.replace("'", '"'))
            if "Literature & Fiction" in categories_list:
                lit_fiction_books.append({
                    'book_id': row['book_id'],
                    'title': row['title']
                })
        except:
            if "Literature & Fiction" in categories_str:
                lit_fiction_books.append({
                    'book_id': row['book_id'],
                    'title': row['title']
                })

# Create sets and mappings
lit_fiction_ids = set(book['book_id'] for book in lit_fiction_books)
book_id_to_title = {book['book_id']: book['title'] for book in lit_fiction_books}

print("Total Literature & Fiction books:", len(lit_fiction_ids))

# Helper to extract numeric ID
def extract_id_number(id_str):
    match = re.search(r'(?:bookid|purchaseid)_?(\d+)', str(id_str))
    if match:
        return int(match.group(1))
    return None

# Check literature & fiction books for perfect ratings
perfect_rating_books = []

for book_id in lit_fiction_ids:
    book_num = extract_id_number(book_id)
    if not book_num:
        continue

    purchase_id = 'purchaseid_' + str(book_num)
    book_reviews = df_reviews[df_reviews['purchase_id'] == purchase_id]

    if len(book_reviews) > 0:
        ratings = pd.to_numeric(book_reviews['rating'], errors='coerce')
        if ratings.notna().sum() > 0:
            avg_rating = ratings.mean()
            if abs(avg_rating - 5.0) < 0.01:
                perfect_rating_books.append({
                    'book_id': book_id,
                    'title': book_id_to_title[book_id],
                    'review_count': len(book_reviews),
                    'avg_rating': float(avg_rating)
                })

print("Perfect 5.0 rating books found:", len(perfect_rating_books))

# Output results
print('__RESULT__:')
print(json.dumps({
    'perfect_books': perfect_rating_books,
    'count': len(perfect_rating_books)
}))
"}

